   602→  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));
   603→
   604→  return tracePath;
   605→}
   606→
   607→/**
   608→ * Pipeline stage mapping for replay functionality
   609→ */
   610→const STAGE_ORDER = [
   611→  'hard-assertions',
   612→  'strong-indicators',
   613→  'rule-scoring',
   614→  'attribute-detection',
   615→  'attribute-influence',
   616→  'disambiguation',
   617→  'multi-label-selection',
   618→  'ai-routing',
   619→  'ai-feature-extraction',
   620→  'ai-classification',
   621→  'final-decision',
   622→] as const;
   623→
   624→type PipelineStage = (typeof STAGE_ORDER)[number];
   625→
   626→/**
   627→ * Load trace data from session directory and validate stage availability
   628→ *
   629→ * @param sessionId - Session ID to load traces from
   630→ * @param replayFromStage - Stage to start replay from
