   607→/**
   608→ * Pipeline stage mapping for replay functionality
   609→ */
   610→const STAGE_ORDER = [
   611→  'hard-assertions',
   612→  'strong-indicators',
   613→  'rule-scoring',
   614→  'attribute-detection',
   615→  'attribute-influence',
   616→  'disambiguation',
   617→  'multi-label-selection',
   618→  'ai-routing',
   619→  'ai-feature-extraction',
   620→  'ai-classification',
   621→  'final-decision',
   622→] as const;
   623→
   624→type PipelineStage = (typeof STAGE_ORDER)[number];
   625→
   626→/**
   627→ * Load trace data from session directory and validate stage availability
   628→ *
   629→ * @param sessionId - Session ID to load traces from
   630→ * @param replayFromStage - Stage to start replay from
   631→ * @returns Array of trace data with email messages and classification results
   632→ */
   633→async function loadSessionTraces(
   634→  sessionId: string,
   635→  replayFromStage: PipelineStage
   636→): Promise<Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }>> {
   637→  const repoRoot = await findRepoRoot();
   638→  const sessionDir = join(repoRoot, 'test-pipeline-results', sessionId);
   639→
   640→  // Check if session directory exists
   641→  try {
   642→    await fs.access(sessionDir);
   643→  } catch {
   644→    throw new Error(`Session directory not found: ${sessionDir}. Please check the session ID.`);
   645→  }
   646→
   647→  // Get all trace files in the session
   648→  const files = await fs.readdir(sessionDir);
   649→  const traceFiles = files.filter((f) => f.endsWith('.json'));
   650→
   651→  if (traceFiles.length === 0) {
   652→    throw new Error(`No trace files found in session ${sessionId}`);
   653→  }
   654→
   655→  console.log(`Found ${traceFiles.length} trace files in session ${sessionId}`);
   656→
   657→  // Load and validate each trace
   658→  const traces: Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }> = [];
   659→
   660→  for (const file of traceFiles) {
   661→    const tracePath = join(sessionDir, file);
   662→
   663→    try {
   664→      const traceContent = await fs.readFile(tracePath, 'utf-8');
   665→      const trace = JSON.parse(traceContent);
   666→
   667→      if (!trace.classificationResult || !trace.messageId) {
   668→        console.warn(`Skipping invalid trace file: ${file}`);
   669→        continue;
   670→      }
   671→
   672→      // Validate that we have enough stage data to replay from the requested stage
   673→      const stageIndex = STAGE_ORDER.indexOf(replayFromStage);
   674→      if (stageIndex === -1) {
   675→        throw new Error(`Invalid stage: ${replayFromStage}. Valid stages: ${STAGE_ORDER.join(', ')}`);
   676→      }
   677→
   678→      // Check that all prior stages have been executed (basic validation)
   679→      const explainabilityTrace = trace.classificationResult.explainabilityTrace;
   680→      const requiredStages = STAGE_ORDER.slice(0, stageIndex);
   681→
   682→      for (const stage of requiredStages) {
   683→        // Map stage names to explainability trace properties
   684→        const hasStageData = getStageData(explainabilityTrace, stage);
   685→        if (!hasStageData) {
   686→          throw new Error(
   687→            `Missing required stage data for ${stage} in ${file}. Cannot replay from ${replayFromStage}.`
   688→          );
   689→        }
   690→      }
   691→
   692→      // Reconstruct email message from trace
   693→      const email: EmailMessage = {
   694→        id: trace.messageId,
   695→        threadId: '',
   696→        gmailLabels: [],
   697→        payload: {
   698→          mimeType: 'text/plain',
   699→          headers: [],
   700→          body: { data: '', size: 0 },
   701→        },
   702→        subject: trace.subject,
   703→        from: { email: trace.from, name: '', raw: trace.from },
   704→        to: [],
   705→        date: new Date(trace.date),
   706→        bodyPlain: trace.classificationResult.bodyContent || '',
   707→        isProcessed: false,
   708→        processingPriority: 0,
   709→      };
   710→
   711→      traces.push({
   712→        email,
   713→        result: trace.classificationResult,
   714→        tracePath,
   715→      });
   716→    } catch (error) {
   717→      console.warn(`Error loading trace file ${file}:`, error instanceof Error ? error.message : String(error));
   718→    }
   719→  }
   720→
   721→  if (traces.length === 0) {
   722→    throw new Error(`No valid trace files found in session ${sessionId}`);
   723→  }
   724→
   725→  console.log(`Successfully loaded ${traces.length} valid traces for replay from ${replayFromStage}`);
   726→  return traces;
   727→}
   728→
   729→/**
   730→ * Check if stage data exists in explainability trace
   731→ */
   732→function getStageData(trace: unknown, stage: PipelineStage): boolean {
   733→  const traceObj = trace as Record<string, unknown>;
   734→  switch (stage) {
   735→    case 'hard-assertions':
   736→      return Array.isArray(traceObj.hardAssertions) && (traceObj.hardAssertions as unknown[]).length >= 0;
   737→    case 'strong-indicators':
   738→      return Array.isArray(traceObj.strongIndicators) && (traceObj.strongIndicators as unknown[]).length >= 0;
   739→    case 'rule-scoring':
   740→      return Array.isArray(traceObj.ruleScoring) && (traceObj.ruleScoring as unknown[]).length >= 0;
   741→    case 'attribute-detection':
   742→      return Array.isArray(traceObj.attributeDetection) && (traceObj.attributeDetection as unknown[]).length >= 0;
   743→    case 'attribute-influence':
   744→      return Array.isArray(traceObj.attributeInfluence) && (traceObj.attributeInfluence as unknown[]).length >= 0;
   745→    case 'disambiguation':
   746→      return Array.isArray(traceObj.disambiguation) && (traceObj.disambiguation as unknown[]).length >= 0;
   747→    case 'multi-label-selection':
   748→      return Array.isArray(traceObj.multiLabelSelection) && (traceObj.multiLabelSelection as unknown[]).length >= 0;
   749→    case 'ai-routing':
   750→      return traceObj.aiRouting !== undefined;
   751→    case 'ai-feature-extraction':
   752→    case 'ai-classification':
   753→    case 'final-decision':
   754→      return true; // These stages can always be replayed
   755→    default:
   756→      return false;
   757→  }
   758→}
