   303→          }
   304→        },
   305→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-label-filtering', replayFromStage),
   306→      },
   307→
   308→      // Stage 9: Action Determination (runs for ALL emails)
   309→      {
   310→        name: 'action-determination',
   311→        execute: async (email, session, result, _config) => {
   312→          await actionDeterminationStage(email, session, result, this.getActionDeterminationConfig());
   313→        },
   314→        shouldSkip: (replayFromStage) => this.shouldSkipStage('action-determination', replayFromStage),
   315→      },
   316→    ];
   317→
   318→    return stageTasks;
   319→  }
