 */

const { ClassificationPipeline, ConfigurationLoader } = require('./packages/classification-engine/dist');
const { join } = require('path');

async function testRefactoredMethods() {
  try {
    console.log('Testing refactored classify() and classifyBatch() methods...\n');

    // Load configuration
    const configLoader = new ConfigurationLoader({
      configDir: join(__dirname, 'config'),
