      threadId: 'thread-001',
      gmailLabels: [],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'noreply@bank.com' },
          { name: 'Subject', value: 'Your account statement is ready' },
          { name: 'Date', value: new Date().toISOString() },
