   192→   * @returns Array of stage tasks in execution order
   193→   */
   194→  private createStageTasks(): StageTask[] {
   195→    const stageTasks: StageTask[] = [
   196→      // Stage 1: Hard Assertions
   197→      {
   198→        name: 'hard-assertions',
   199→        execute: async (email, session, result, _config) => {
   200→          executeHardAssertions(email, session, result, this.getHardAssertionConfig());
   201→        },
   202→        shouldSkip: (replayFromStage) => this.shouldSkipStage('hard-assertions', replayFromStage),
   203→      },
   204→
   205→      // Stage 2: Strong Indicators
   206→      {
   207→        name: 'strong-indicators',
   208→        execute: async (email, session, result, _config) => {
   209→          executeStrongIndicators(email, session, result, this.getStrongIndicatorConfig());
   210→        },
   211→        shouldSkip: (replayFromStage) => this.shouldSkipStage('strong-indicators', replayFromStage),
   212→      },
   213→
   214→      // Stage 3: Rule Scoring
   215→      {
   216→        name: 'rule-scoring',
   217→        execute: async (email, session, result, _config) => {
   218→          executeRuleScoring(email, session, result, this.getRuleScoringConfig());
   219→        },
   220→        shouldSkip: (replayFromStage) => this.shouldSkipStage('rule-scoring', replayFromStage),
   221→      },
   222→
   223→      // Stage 4: Attribute Detection
   224→      {
   225→        name: 'attribute-detection',
   226→        execute: async (email, session, result, _config) => {
   227→          executeAttributeDetection(email, session, result, this.getAttributeDetectionConfig());
   228→        },
   229→        shouldSkip: (replayFromStage) => this.shouldSkipStage('attribute-detection', replayFromStage),
   230→      },
   231→
   232→      // Stage 5: Attribute Influence
   233→      {
   234→        name: 'attribute-influence',
   235→        execute: async (email, session, result, _config) => {
   236→          executeAttributeInfluence(email, session, result, this.config);
   237→        },
   238→        shouldSkip: (replayFromStage) => this.shouldSkipStage('attribute-influence', replayFromStage),
   239→      },
   240→
   241→      // Stage 6: Disambiguation
   242→      {
   243→        name: 'disambiguation',
   244→        execute: async (email, session, result, _config) => {
   245→          executeDisambiguation(email, session, result, this.config);
   246→        },
   247→        shouldSkip: (replayFromStage) => this.shouldSkipStage('disambiguation', replayFromStage),
   248→      },
   249→
   250→      // Stage 7: Multi-label Selection
   251→      {
   252→        name: 'multi-label-selection',
   253→        execute: async (email, session, result, _config) => {
   254→          executeMultiLabelSelection(
   255→            email,
   256→            session,
   257→            result,
   258→            this.getMultiLabelConfig(),
   259→            this.getConfidenceThresholds()
   260→          );
   261→        },
   262→        shouldSkip: (replayFromStage) => this.shouldSkipStage('multi-label-selection', replayFromStage),
   263→      },
   264→
   265→      // Stage 8a: AI Routing
   266→      {
   267→        name: 'ai-routing',
   268→        execute: async (email, session, result, _config) => {
   269→          aiRoutingStage(email, session, result, this.getAIRoutingConfig());
   270→        },
   271→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-routing', replayFromStage),
   272→      },
   273→
   274→      // Stage 8b: AI Feature Extraction (conditional)
   275→      {
   276→        name: 'ai-feature-extraction',
   277→        execute: async (email, session, result, _config) => {
   278→          if (result.needsAiClassification) {
   279→            await aiFeatureExtractionStage(email, session, result, this.getAIFeatureExtractionConfig());
   280→          }
   281→        },
   282→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-feature-extraction', replayFromStage),
   283→      },
   284→
   285→      // Stage 8c: AI Classification (conditional)
   286→      {
   287→        name: 'ai-classification',
   288→        execute: async (email, session, result, _config) => {
   289→          if (result.needsAiClassification) {
   290→            await aiClassificationStage(email, session, result, this.getAIClassificationConfig());
   291→          }
   292→        },
   293→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-classification', replayFromStage),
   294→      },
   295→
   296→      // Stage 8d: AI Label Filtering (conditional)
   297→      {
   298→        name: 'ai-label-filtering',
   299→        execute: async (email, session, result, _config) => {
   300→          if (result.needsAiClassification) {
   301→            await aiLabelFilteringStage(email, session, result, this.getAILabelFilteringConfig());
   302→          }
   303→        },
   304→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-label-filtering', replayFromStage),
   305→      },
   306→
   307→      // Stage 9: Action Determination (runs for ALL emails)
   308→      {
   309→        name: 'action-determination',
   310→        execute: async (email, session, result, _config) => {
   311→          await actionDeterminationStage(email, session, result, this.getActionDeterminationConfig());
   312→        },
   313→        shouldSkip: (replayFromStage) => this.shouldSkipStage('action-determination', replayFromStage),
   314→      },
   315→    ];
   316→
   317→    return stageTasks;
   318→  }
