   320→  /**
   321→   * Execute classification pipeline using StageTask architecture with optional replay support
   322→   *
   323→   * Provides the foundation for true replay-from-stage functionality by iterating
   324→   * through stage tasks and selectively skipping stages based on replay parameters.
   325→   *
   326→   * @param email - Email message to classify
   327→   * @param replayFromStage - Optional stage name to start replay from
   328→   * @returns Complete classification result with selected labels
   329→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   330→   */
   331→  async classifyWithStageTask(email: EmailMessage, replayFromStage?: string): Promise<ClassificationResult> {
   332→    const pipelineStartTime = Date.now();
   333→
   334→    try {
   335→      // Validate email input
   336→      validateEmailInput(email);
   337→
   338→      // Create classification session for single email
   339→      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);
   340→
   341→      // Create classification result
   342→      const result = createClassificationResult(email.id, session.id, 0);
   343→
   344→      // Get stage tasks array
   345→      const stageTasks = this.createStageTasks();
   346→
   347→      // Execute stages using StageTask architecture
   348→      for (const stageTask of stageTasks) {
   349→        // Check if this stage should be skipped for replay
   350→        if (stageTask.shouldSkip(replayFromStage)) {
   351→          // Log stage skipping only in test mode for debugging
   352→          if (this.testMode && replayFromStage) {
   353→            console.log(`Skipping stage: ${stageTask.name} (replay from: ${replayFromStage})`);
   354→          }
   355→          continue;
   356→        }
   357→
   358→        // Log stage execution only in test mode for debugging
   359→        if (this.testMode) {
   360→          console.log(`Executing stage: ${stageTask.name}`);
   361→        }
   362→
   363→        // Execute the stage (maintains canonical signature pattern)
   364→        try {
   365→          await stageTask.execute(email, session, result, this.config);
   366→        } catch (error) {
   367→          throw new Error(
   368→            `Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`
   369→          );
   370→        }
   371→      }
   372→
   373→      // Mark session as successful
   374→      incrementSessionSuccess(session);
   375→      finalizeClassificationSession(session);
   376→
   377→      // Update final processing time
   378→      result.processingDurationMs = Date.now() - pipelineStartTime;
   379→      result.processedAt = new Date();
   380→
   381→      return result;
   382→    } catch (error) {
   383→      // Capture error with processing time
   384→      const pipelineEndTime = Date.now();
   385→      throw new Error(
   386→        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
   387→      );
   388→    }
   389→  }
