 * Unit Tests for StageTask Architecture
 *
 * Comprehensive tests for the new StageTask interface, replay-from-stage functionality,
 * and stage skipping logic implemented in T036p.
 */

import { ClassificationPipeline } from '../../src/pipeline/classification-pipeline';
import { EmailMessage } from '../../src/types/email-message';
import { ProcessingConfig, CategoryConfiguration } from '../../src/types/category-configuration';

describe('StageTask Architecture', () => {
  // Mock email message for testing
  const mockEmail: EmailMessage = {
    id: 'stage-task-test-001',
    threadId: 'thread-001',
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test StageTask Email' },
        { name: 'From', value: 'test@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toISOString() },
      ],
      body: {
        data: Buffer.from('Test email body for StageTask testing').toString('base64url'),
      },
    },
    subject: 'Test StageTask Email',
    from: { email: 'test@example.com', name: 'Test User', raw: 'Test User <test@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date(),
    bodyPlain: 'Test email body for StageTask testing',
    isProcessed: false,
    processingPriority: 1,
  };

  // Load the actual test configuration to avoid incomplete config issues
  let testConfig: CategoryConfiguration;

  beforeAll(async () => {
    const { ConfigurationLoader } = require('../../src/config/configuration-loader');
    const { join } = require('path');

    // Find the project root config directory
    const configDir = join(__dirname, '../../../config');
    const configLoader = new ConfigurationLoader({
      configDir,
      enableHotReload: false,
      validateOnLoad: true,
    });

    const categoryConfigResult = await configLoader.loadCategoryConfiguration();
    if (!categoryConfigResult.validationPassed) {
      throw new Error(`Configuration validation failed: ${categoryConfigResult.validationErrors.join('\n')}`);
    }

    testConfig = categoryConfigResult.config as CategoryConfiguration;

    // Override AI settings to avoid OpenAI issues in tests
    testConfig.processingConfig.settings.aiRouting.enableAiClassification = false;
  });

  let pipeline: ClassificationPipeline;

  beforeEach(() => {
    pipeline = new ClassificationPipeline(minimalConfig, true); // Enable test mode
  });

  describe('classifyWithStageTask Method', () => {
    it('should exist and be callable', () => {
      expect(typeof pipeline.classifyWithStageTask).toBe('function');
    });

    it('should execute full pipeline when no replay stage specified', async () => {
      const result = await pipeline.classifyWithStageTask(mockEmail);

      expect(result).toBeDefined();
      expect(result.emailId).toBe(mockEmail.id);
      expect(result.selectedLabels).toBeDefined();
      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.processedAt).toBeInstanceOf(Date);
    });

    it('should handle replay from specific stage', async () => {
      // Test replay from multi-label-selection stage
      const result = await pipeline.classifyWithStageTask(mockEmail, 'multi-label-selection');

      expect(result).toBeDefined();
      expect(result.emailId).toBe(mockEmail.id);
      expect(result.selectedLabels).toBeDefined();
    });

    it('should skip stages before replay point', async () => {
      // Spy on console.log to verify stage skipping messages
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail, 'attribute-detection');

        // Should have skip messages for earlier stages
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Skipping stage: hard-assertions'));
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Skipping stage: strong-indicators'));
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Skipping stage: rule-scoring'));

        // Should execute from attribute-detection onwards
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Executing stage: attribute-detection'));
      } finally {
        consoleSpy.mockRestore();
      }
    });

    it('should handle invalid replay stage gracefully', async () => {
      // Test with non-existent stage name
      const result = await pipeline.classifyWithStageTask(mockEmail, 'invalid-stage');

      // Should execute all stages (invalid stage is ignored)
      expect(result).toBeDefined();
      expect(result.emailId).toBe(mockEmail.id);
    });

    it('should provide stage-specific error messages', async () => {
      // Create a mock that will cause an error in a specific stage
      const mockEmailWithError = { ...mockEmail, id: undefined as any };

      await expect(pipeline.classifyWithStageTask(mockEmailWithError)).rejects.toThrow(
        /Classification pipeline failed/
      );
    });
  });

  describe('Stage Skipping Logic', () => {
    it('should skip all stages before replay point', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail, 'disambiguation');

        // Verify specific stages are skipped
        const skippedStages = [
          'hard-assertions',
          'strong-indicators',
          'rule-scoring',
          'attribute-detection',
          'attribute-influence',
        ];

        skippedStages.forEach((stage) => {
          expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining(`Skipping stage: ${stage}`));
        });

        // Verify disambiguation and later stages execute
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Executing stage: disambiguation'));
      } finally {
        consoleSpy.mockRestore();
      }
    });

    it('should execute all stages when no replay specified', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail);

        // Should not have any skip messages
        expect(consoleSpy).not.toHaveBeenCalledWith(expect.stringContaining('Skipping stage:'));

        // Should execute from first stage
        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Executing stage: hard-assertions'));
      } finally {
        consoleSpy.mockRestore();
      }
    });
  });

  describe('Stage Order Validation', () => {
    it('should respect STAGE_ORDER constant', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail);

        // Verify stages execute in correct order
        const calls = consoleSpy.mock.calls
          .filter((call) => call[0].includes('Executing stage:'))
          .map((call) => call[0]);

        // Should start with hard-assertions
        expect(calls[0]).toContain('Executing stage: hard-assertions');
        expect(calls[1]).toContain('Executing stage: strong-indicators');
        expect(calls[2]).toContain('Executing stage: rule-scoring');
      } finally {
        consoleSpy.mockRestore();
      }
    });
  });

  describe('Integration with Existing Methods', () => {
    it('should maintain consistency between classify() and classifyWithStageTask()', async () => {
      const directResult = await pipeline.classifyWithStageTask(mockEmail);
      const delegatedResult = await pipeline.classify(mockEmail);

      // Results should have similar structure (though session IDs will differ)
      expect(directResult.emailId).toBe(delegatedResult.emailId);
      expect(directResult.selectedLabels.length).toBe(delegatedResult.selectedLabels.length);
      expect(typeof directResult.processingDurationMs).toBe(typeof delegatedResult.processingDurationMs);
    });

    it('should work correctly in batch processing', async () => {
      const emails = [
        mockEmail,
        { ...mockEmail, id: 'stage-task-test-002' },
        { ...mockEmail, id: 'stage-task-test-003' },
      ];

      const results = await pipeline.classifyBatch(emails);

      expect(results).toHaveLength(3);
      results.forEach((result, index) => {
        if ('emailId' in result) {
          expect(result.emailId).toBe(emails[index].id);
          expect(result.selectedLabels).toBeDefined();
        }
      });
    });
  });

  describe('Error Handling and Edge Cases', () => {
    it('should handle empty email gracefully', async () => {
      const emptyEmail = { ...mockEmail, subject: '', bodyPlain: '' };

      const result = await pipeline.classifyWithStageTask(emptyEmail);
      expect(result).toBeDefined();
      expect(result.emailId).toBe(emptyEmail.id);
    });

    it('should preserve session tracking in test mode', async () => {
      const result = await pipeline.classifyWithStageTask(mockEmail);

      expect(result.sessionId).toBeDefined();
      expect(typeof result.sessionId).toBe('string');
      expect(result.batchPosition).toBe(0);
    });

    it('should handle stage execution errors gracefully', async () => {
      // Test with malformed email that might cause stage errors
      const malformedEmail = {
        ...mockEmail,
        payload: {
          ...mockEmail.payload,
          headers: undefined as any,
        },
      };

      // Should either succeed or fail with descriptive error
      try {
        const result = await pipeline.classifyWithStageTask(malformedEmail);
        expect(result).toBeDefined();
      } catch (error) {
        expect(error).toBeInstanceOf(Error);
        expect((error as Error).message).toContain('Classification pipeline failed');
      }
    });
  });

  describe('Performance and Timing', () => {
    it('should track processing duration accurately', async () => {
      const startTime = Date.now();
      const result = await pipeline.classifyWithStageTask(mockEmail);
      const endTime = Date.now();

      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.processingDurationMs).toBeLessThanOrEqual(endTime - startTime + 100); // 100ms tolerance
    });

    it('should complete replay processing efficiently', async () => {
      const startTime = Date.now();
      await pipeline.classifyWithStageTask(mockEmail, 'multi-label-selection');
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(10000); // Should complete within 10 seconds
    });
  });
});

