  describe('Stage Order and Architecture', () => {
    it('should maintain consistent stage execution order', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail);
      } catch (error) {
        // Expected failure
      }

      try {
        const logCalls = consoleSpy.mock.calls.map(call => call[0]);
        const executeMessages = logCalls.filter(msg => msg.includes('Executing stage:'));

        // Verify stages execute in expected order
        if (executeMessages.length >= 3) {
          expect(executeMessages[0]).toContain('hard-assertions');
